const body = $input.first().json.body;

if (!body.user_id)      throw new Error('user_id is required');
if (!body.job_name)     throw new Error('job_name is required');
if (!body.search_query) throw new Error('search_query is required');
if (!body.location)     throw new Error('location is required');
if (!body.max_results)  throw new Error('max_results is required');

const maxResults = parseInt(body.max_results);
if (maxResults < 1 || maxResults > 500)
  throw new Error('max_results must be 1-500');

return {
  user_id:      parseInt(body.user_id),
  job_name:     body.job_name,
  source:       'google_maps',
  search_query: body.search_query,
  location:     body.location,
  max_results:  maxResults
};

const user    = $input.first().json;
const request = $('Validate Request').first().json;

if (!user || !user.id) {
  return { error: true, code: 'USER_NOT_FOUND', message: 'User not found' };
}
if (!user.apify_api_key) {
  return { error: true, code: 'APIFY_NOT_CONNECTED', message: 'Please connect Apify account first' };
}
if (user.apify_status !== 'active') {
  return { error: true, code: 'APIFY_INVALID', message: 'Apify key is invalid or inactive' };
}

const estimatedCost = (request.max_results / 100) * 0.01;

if (parseFloat(user.apify_credit) < estimatedCost) {
  return {
    error: true,
    code: 'INSUFFICIENT_CREDIT',
    message: `Need $${estimatedCost.toFixed(4)}, have $${parseFloat(user.apify_credit).toFixed(2)}`
  };
}

return {
  error:          false,
  user_id:        user.id,
  apify_api_key:  user.apify_api_key,
  estimated_cost: estimatedCost,
  job_name:       request.job_name,
  source:         'google_maps',
  search_query:   request.search_query,
  location:       request.location,
  max_results:    request.max_results
};

const job      = $input.first().json;
const apifyKey = $('Check Apify Status').first().json.apify_api_key;

const jobId = job.id || job.job_id;
if (!jobId)    throw new Error('job_id missing from DB insert');
if (!apifyKey) throw new Error('Apify key missing');

return {
  job_id:        jobId,
  user_id:       job.user_id,
  apify_api_key: apifyKey,
  search_query:  job.search_query,
  location:      job.location,
  max_results:   job.max_results
};

